constexpr auto DEF_VECTOR_SIZE_PER_THREAD = 4 * 1024 * 1024;

using ArgParams = struct { unsigned int vecwidth; };

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {

        case 0:
          output->vecwidth = value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

// CUDA Kernel Implementation
template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_block_kernel(Element* data, Element* sum_ptr) {
  Element sum = 0;

  // Use first 8 elements as f array (similar to non-BASELINE_IMPL)
  Element f[8];
  for(int k=0; k<8; k++) {
    f[k] = data[k];
  }

  size_t idx = blockIdx.x * static_chunk_size + threadIdx.x;
  size_t total_chunks = (static_chunk_size * blockDim.x);

  // Process one chunk per thread
  if (idx < static_chunk_size) {
    Element t[8];
    for(int k=0; k<8; k++) t[k] = data[idx];

    size_t iterations = compute_iterations / 8;
    for (size_t j = 0; j < iterations; j++) {
      t[0] = t[0] * t[0] + f[0];
      t[1] = t[1] * t[1] + f[1];
      t[2] = t[2] * t[2] + f[2];
      t[3] = t[3] * t[3] + f[3];
      t[4] = t[4] * t[4] + f[4];
      t[5] = t[5] * t[5] + f[5];
      t[6] = t[6] * t[6] + f[6];
      t[7] = t[7] * t[7] + f[7];
    }

    if constexpr (compute_iterations % 8 > 0) {
      t[0] = t[0] * t[0] + f[0];
    }
    if constexpr (compute_iterations % 8 > 1) {
      t[1] = t[1] * t[1] + f[1];
    }
    if constexpr (compute_iterations % 8 > 2) {
      t[2] = t[2] * t[2] + f[2];
    }
    if constexpr (compute_iterations % 8 > 3) {
      t[3] = t[3] * t[3] + f[3];
    }
    if constexpr (compute_iterations % 8 > 4) {
      t[4] = t[4] * t[4] + f[4];
    }
    if constexpr (compute_iterations % 8 > 5) {
      t[5] = t[5] * t[5] + f[5];
    }
    if constexpr (compute_iterations % 8 > 6) {
      t[6] = t[6] * t[6] + f[6];
    }

    sum += t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];
  }

  // Simple reduction within block
  __shared__ Element block_sum[1024];
  block_sum[threadIdx.x] = sum;
  __syncthreads();

  if (threadIdx.x == 0) {
    Element local_sum = 0;
    for(int i=0; i<blockDim.x; i++) {
      local_sum += block_sum[i];
    }
    *sum_ptr += local_sum;
  }
}

template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, const Element seed1, const Element seed2, Element* src_device, Element* src_host) {
  constexpr size_t static_chunk_size = 4096;

  // Initialize data on host
  for(size_t i=0; i<len; i++) {
    src_host[i] = (i % 2 == 0) ? seed1 : seed2;
  }

  // Copy to device
  cudaMemcpy(src_device, src_host, len * sizeof(Element), cudaMemcpyHostToDevice);

  Element sum_host = 0;
  Element* sum_device;
  cudaMalloc(&sum_device, sizeof(Element));
  cudaMemcpy(sum_device, &sum_host, sizeof(Element), cudaMemcpyHostToDevice);

  int threads_per_block = 256;
  int blocks = (static_chunk_size + threads_per_block - 1) / threads_per_block;

  // Launch kernel for each chunk
  size_t total_chunks = (len + static_chunk_size - 1) / static_chunk_size;
  int total_blocks = total_chunks * blocks;

  bench_block_kernel<Element, compute_iterations, static_chunk_size><<<total_blocks, threads_per_block>>>(src_device, sum_device);

  cudaMemcpy(&sum_host, sum_device, sizeof(Element), cudaMemcpyDeviceToHost);

  *src_host = sum_host;

  cudaFree(sum_device);

  return len;
}

using benchmark_clock = std::chrono::steady_clock;

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);
  auto timer_start = benchmark_clock::now();

  double* ptr_host = (double*)c;
  double* ptr_device;
  cudaMalloc(&ptr_device, num_elements * sizeof(double));

  bench_cuda<double, 16>(num_elements, 1., -1., ptr_device, ptr_host);

  cudaFree(ptr_device);

  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;

  auto duration = op();  
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, compute_iterations};

  // Allocate device memory
  float* c_as_float_device;
  double* c_as_double_device;
  int* c_as_int_device;

  cudaMalloc(&c_as_float_device, cs.element_count<float>() * sizeof(float));
  cudaMalloc(&c_as_double_device, cs.element_count<double>() * sizeof(double));
  cudaMalloc(&c_as_int_device, cs.element_count<int>() * sizeof(int));

  float* c_as_float_host = (float*)c;
  double* c_as_double_host = (double*)c;
  int* c_as_int_host = (int*)c;

  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, c_as_float_device, c_as_float_host);
    });
  });

  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<double, compute_iterations>(cs.element_count<double>(), 1., -1., c_as_double_device, c_as_double_host);
    });
  });

  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int_device, c_as_int_host);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;

  cudaFree(c_as_float_device);
  cudaFree(c_as_double_device);
  cudaFree(c_as_int_device);
}

template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* cd, size_t size) {
  runbench_range<j1>(cd, size);
  runbench_range<j2, Args...>(cd, size);
}

void mixbenchCPU(void* c, size_t size) {
  // Initialize memory on GPU
  int* c_int;
  cudaMalloc(&c_int, size);
  cudaMemset(c_int, 0, size);
  cudaFree(c_int);

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(c, size);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8,
                 8 * 8, 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8,
                 40 * 8, 64 * 8>(c, size);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;
}

int main(int argc, char* argv[]) {
  std::cout << "mixbench-cuda (" << VERSION_INFO << ")" << std::endl;

  // Get GPU info
  cudaSetDevice(0);
  StoreDeviceInfo(stdout);

  size_t freeCUDAMem, totalCUDAMem;
  cudaMemGetInfo(&freeCUDAMem, &totalCUDAMem);
  printf("Total GPU memory %lu, free %lu\n", totalCUDAMem, freeCUDAMem);

  ArgParams args{static_cast<unsigned int>(
      DEF_VECTOR_SIZE_PER_THREAD / (1024 * 1024))};

  if (!argument_parsing(argc, argv, &args)) {
    std::cout << "Usage: mixbench-cuda [options] [array size(1024^2)]"
              << std::endl
              << std::endl
              << "Options:" << std::endl
              << "  -h or --help              Show this message" << std::endl;

    exit(1);
  }

  std::cout << "Use \"-h\" argument to see available options" << std::endl;

  const size_t VEC_WIDTH = 1024 * 1024 * args.vecwidth;

  std::unique_ptr<std::byte[]> c;
  c.reset(new (std::align_val_t(64)) std::byte[VEC_WIDTH * sizeof(double)]);

  std::cout << "Working memory size: " << args.vecwidth * sizeof(double) << "MB"
            << std::endl;

  mixbenchCPU(c.get(), VEC_WIDTH * sizeof(double));

  return 0;
}
